Got it! Here’s how you can generate the code verifier and code challenge in Swift:

```swift
import Foundation

func generateCodeVerifier() -> String {
    let characters = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789-_.~"
    var codeVerifier = ""
    for _ in 0..<128 { // 128 is the max length for PKCE code verifier
        if let randomCharacter = characters.randomElement() {
            codeVerifier.append(randomCharacter)
        }
    }
    return codeVerifier
}

func generateCodeChallenge(from codeVerifier: String) -> String? {
    guard let verifierData = codeVerifier.data(using: .utf8) else { return nil }

    // Hash the code verifier using SHA256
    var hash = Data(count: Int(CC_SHA256_DIGEST_LENGTH))
    _ = hash.withUnsafeMutableBytes { hashBytes in
        verifierData.withUnsafeBytes { verifierBytes in
            CC_SHA256(verifierBytes.baseAddress, CC_LONG(verifierData.count), hashBytes.bindMemory(to: UInt8.self).baseAddress)
        }
    }

    // Encode the hash using base64 URL encoding
    let base64EncodedHash = hash.base64EncodedString(options: .endLineWithLineFeed)
    let codeChallenge = base64EncodedHash
        .replacingOccurrences(of: "=", with: "")
        .replacingOccurrences(of: "+", with: "-")
        .replacingOccurrences(of: "/", with: "_")

    return codeChallenge
}

// Usage
let codeVerifier = generateCodeVerifier()
if let codeChallenge = generateCodeChallenge(from: codeVerifier) {
    print("Code Verifier: \(codeVerifier)")
    print("Code Challenge: \(codeChallenge)")
} else {
    print("Failed to generate code challenge")
}
```

This code uses the CommonCrypto library to perform the SHA-256 hashing. The base64-url encoding is handled by replacing characters from the standard base64 output. Make sure your app has the necessary imports and permissions to use CommonCrypto.

