export const getStaticProps = async ({ params }) => {
  const slug = params.slug || [];
  const breadcrumbs = slug.map((segment, index) => {
    const breadcrumbPath = `/${slug.slice(0, index + 1).join('/')}`;
    return { name: segment, path: breadcrumbPath };
  });

  return {
    props: {
      breadcrumbs,
    },
  };
};
```

