const { Text, Title } = Typography;

const STATUS_CONFIG = {
  pending: { color: 'orange', label: '待确认' },
  confirmed: { color: 'green', label: '已确认' },
  cancelled: { color: 'red', label: '已取消' },
};

interface BookingListProps {
  bookings: Booking[];
  loading: boolean;
}

const BookingList: React.FC<BookingListProps> = ({ bookings, loading }) => {
  if (loading) {
    return <Spin size="large" style={{ display: 'block', margin: '50px auto' }} />;
  }

  if (bookings.length === 0) {
    return <Empty description="暂无预约记录" />;
  }

  // 按日期分组
  const groupedBookings = bookings.reduce((groups, booking) => {
    const date = booking.date;
    if (!groups[date]) {
      groups[date] = [];
    }
    groups[date].push(booking);
    return groups;
  }, {} as Record<string, Booking[]>);

  // 按日期排序
  const sortedDates = Object.keys(groupedBookings).sort();

  return (
    <div>
      {sortedDates.map(date => (
        <div key={date} style={{ marginBottom: 24 }}>
          <Title level={4} style={{ borderBottom: '2px solid #1890ff', paddingBottom: 8 }}>
            {dayjs(date).format('YYYY年MM月DD日 dddd')}
            <Badge count={groupedBookings[date].length} style={{ marginLeft: 12 }} />
          </Title>
          <List
            grid={{ gutter: 16, xs: 1, sm: 2, md: 3, lg: 3 }}
            dataSource={groupedBookings[date]}
