   ```

2. **Add a Scheduler Function**:
   - When a new task is created, you can schedule a job for that task based on its `schedule_time`.
   - You’ll also need to handle the case where the server restarts — simply reschedule jobs for all reminders in the database.

3. **Sending Reminders**:
   - For simplicity, we’ll simulate reminder notifications by logging them to the console. In a real-world app, you could use something like email or push notifications.

Here’s how to extend your current API code:

```javascript
const schedule = require('node-schedule');

// Store scheduled jobs in memory
const scheduledJobs = {};

// Function to schedule a reminder
function scheduleReminder(taskId, scheduleTime, title, description) {
  const job = schedule.scheduleJob(scheduleTime, () => {
    console.log(`Reminder: ${title} - ${description}`);

    // You can replace this with logic to send an email or push notification
  });

  // Save the job reference for potential cancellation
  scheduledJobs[taskId] = job;
}

// When creating a new task, schedule a reminder
app.post('/tasks', authenticateToken, (req, res) => {
  const { title, description, schedule_time } = req.body;
  const userId = req.user.id;

  db.run(
    'INSERT INTO tasks (user_id, title, description, schedule_time) VALUES (?, ?, ?, ?)',
    [userId, title, description, schedule_time],
    function (err) {
      if (err) {
        return res.status(500).json({ message: 'Error creating task.' });
      }

      // Schedule the reminder
      const taskId = this.lastID;
      scheduleReminder(taskId, new Date(schedule_time), title, description);

      res.status(201).json({ taskId });
    }
  );
});

// Handle server restart by rescheduling jobs
db.all('SELECT * FROM tasks', (err, tasks) => {
  if (err) {
    console.error('Error loading tasks:', err);
  } else {
    tasks.forEach(task => {
      scheduleReminder(
        task.id,
        new Date(task.schedule_time),
        task.title,
        task.description
      );
    });
  }
});

// Optional: Cancel a scheduled reminder
app.delete('/tasks/:id', authenticateToken, (req, res) => {
  const taskId = req.params.id;
  const userId = req.user.id;

  db.run('DELETE FROM tasks WHERE id = ? AND user_id = ?', [taskId, userId], function (err) {
    if (err || this.changes === 0) {
      return res.status(404).json({ message: 'Task not found.' });
    }

    // Cancel the corresponding job if it exists
    if (scheduledJobs[taskId]) {
      scheduledJobs[taskId].cancel();
      delete scheduledJobs[taskId];
    }

    res.json({ message: 'Task deleted successfully.' });
  });
});
```

### Key Notes:
- The `scheduleReminder` function uses `node-schedule` to schedule a job based on the `schedule_time` field.
- When the server restarts, it reschedules jobs for all tasks in the database.
- Reminders are currently simulated with `console.log`. You can integrate email notifications using a library like `nodemailer` or push notifications using services like Firebase Cloud Messaging.
- Jobs are stored in the `scheduledJobs` object, allowing you to cancel them if a task is deleted.

