   ```
   This column could hold values like `daily`, `weekly`, or a custom cron expression.

2. **Handle Recurring Schedules in Code**:
   In the `scheduleReminder` function, adjust its behavior to support recurring jobs based on the `recurrence` field.

3. **Code Example**:
   Modify the reminder logic to account for recurrence patterns:

```javascript
function scheduleRecurringReminder(taskId, scheduleTime, title, description, recurrence) {
  let job;

  if (recurrence === 'daily') {
    job = schedule.scheduleJob({ hour: scheduleTime.getHours(), minute: scheduleTime.getMinutes() }, () => {
      console.log(`Daily Reminder: ${title} - ${description}`);
      // Add notification logic here
    });
  } else if (recurrence === 'weekly') {
    job = schedule.scheduleJob({ dayOfWeek: scheduleTime.getDay(), hour: scheduleTime.getHours(), minute: scheduleTime.getMinutes() }, () => {
      console.log(`Weekly Reminder: ${title} - ${description}`);
      // Add notification logic here
    });
  } else if (recurrence) {
    // Handle custom cron expression
    job = schedule.scheduleJob(recurrence, () => {
      console.log(`Custom Recurring Reminder: ${title} - ${description}`);
      // Add notification logic here
    });
  } else {
    // Default: one-time reminder
    job = schedule.scheduleJob(scheduleTime, () => {
      console.log(`One-Time Reminder: ${title} - ${description}`);
      // Add notification logic here
    });
  }

  // Save the job reference
  scheduledJobs[taskId] = job;
}

// Example Task Creation Endpoint (with recurrence)
app.post('/tasks', authenticateToken, (req, res) => {
  const { title, description, schedule_time, recurrence } = req.body;
  const userId = req.user.id;

  db.run(
    'INSERT INTO tasks (user_id, title, description, schedule_time, recurrence) VALUES (?, ?, ?, ?, ?)',
    [userId, title, description, schedule_time, recurrence],
    function (err) {
      if (err) {
        return res.status(500).json({ message: 'Error creating task.' });
      }

      const taskId = this.lastID;

      // Schedule the reminder based on recurrence pattern
      scheduleRecurringReminder(
        taskId,
        new Date(schedule_time),
        title,
        description,
        recurrence
      );

      res.status(201).json({ taskId });
    }
  );
});

// Reschedule reminders at server restart
function rescheduleTasksOnStartup() {
  db.all('SELECT * FROM tasks', (err, tasks) => {
    if (err) {
      console.error('Error loading tasks:', err);
    } else {
      tasks.forEach(task => {
        scheduleRecurringReminder(
          task.id,
          new Date(task.schedule_time),
          task.title,
          task.description,
          task.recurrence
        );
      });
    }
  });
}

rescheduleTasksOnStartup();
```

### Key Points:
- **Recurrence Patterns**: The `recurrence` field supports predefined patterns (`daily`, `weekly`) or custom cron-like expressions.
- **Custom Logic**: For advanced recurring reminders, users can provide cron expressions (e.g., `0 9 * * 1` for every Monday at 9 AM).
- **Simplified Management**:
