4. **Track the Logged-In User in Your Chat App:**
   - Update the `ChatApp.vue` file to track the current user:
     ```javascript
     import { onAuthStateChanged } from 'firebase/auth';
     import { auth } from '@/firebase';

     export default {
       data() {
         return {
           user: null,
           messages: [],
           newMessage: ''
         };
       },
       methods: {
         async sendMessage() {
           if (this.newMessage.trim() !== '' && this.user) {
             const messagesRef = collection(db, 'messages');
             await addDoc(messagesRef, {
               text: this.newMessage,
               sender: this.user.email, // Store the sender's email
               timestamp: new Date()
             });
             this.newMessage = '';
           }
         }
       },
       mounted() {
         onAuthStateChanged(auth, (user) => {
           this.user = user;
           if (!user) {
             this.$router.push('/login'); // Redirect to login if not authenticated
           }
         });

         const q = query(collection(db, 'messages'), orderBy('timestamp'));
         onSnapshot(q, (snapshot) => {
           this.messages = snapshot.docs.map((doc) => ({ id: doc.id, ...doc.data() }));
         });
       }
     };
     ```

5. **Display the Sender's Name:**
   - Update the message list to display the sender:
     ```vue
     <v-list-item v-for="message in messages" :key="message.id">
       <v-list-item-content>
         <v-list-item-title>{{ message.sender }}</v-list-item-title>
         <v-list-item-subtitle>{{ message.text }}</v-list-item-subtitle>
       </v-list-item-content>
     </v-list-item>
     ```

6. **Sign Out Functionality:**
   - Add a logout button to allow users to sign out:
     ```vue
     <v-btn @click="logout" color="secondary">Logout</v-btn>

     <script>
     import { signOut } from 'firebase/auth';
     import { auth } from '@/firebase';

     methods: {
       async logout() {
         await signOut(auth);
         this.$router.push('/login');
       }
     }
     </script>
     ```

Now each message will show the email of the logged-in user who sent it. You can later extend this to display usernames or other profile information. Let me know if you'd like to dive deeper into customizing the user experience or handling additional features like registration!

