Absolutely! Here's how you can generate the code verifier and code challenge in Swift:

```swift
import Foundation

// Step 1: Generate a Code Verifier
func generateCodeVerifier() -> String {
    let characters = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789-._~"
    let length = 128 // Length of the code verifier, between 43 and 128 characters
    var codeVerifier = ""
    for _ in 0..<length {
        guard let randomCharacter = characters.randomElement() else { continue }
        codeVerifier.append(randomCharacter)
    }
    return codeVerifier
}

// Step 2: Generate the Code Challenge
func generateCodeChallenge(from codeVerifier: String) -> String? {
    guard let data = codeVerifier.data(using: .utf8) else { return nil }

    // Use SHA256 to hash the verifier
    var hashedData = Data(count: Int(CC_SHA256_DIGEST_LENGTH))
    _ = hashedData.withUnsafeMutableBytes { hashedBytes in
        data.withUnsafeBytes { messageBytes in
            CC_SHA256(messageBytes.baseAddress, CC_LONG(data.count), hashedBytes.bindMemory(to: UInt8.self).baseAddress)
        }
    }

    // Base64 encode the hash in a URL-safe format, removing padding
    return hashedData.base64EncodedString()
        .replacingOccurrences(of: "+", with: "-")
        .replacingOccurrences(of: "/", with: "_")
        .replacingOccurrences(of: "=", with: "")
}

// Example usage
let codeVerifier = generateCodeVerifier()
print("Code Verifier: \(codeVerifier)")

if let codeChallenge = generateCodeChallenge(from: codeVerifier) {
    print("Code Challenge: \(codeChallenge)")
} else {
    print("Failed to generate the code challenge.")
}
```

In this example:
1. The `generateCodeVerifier` function creates a random, high-entropy string using a pool of allowed characters.
2. The `generateCodeChallenge` function hashes the `code_verifier` using SHA-256 and then encodes the result in a URL-safe Base64 format.

Make sure to include the CommonCrypto library for the SHA-256 hashing. You’ll need to import it in your bridging header if you’re working in Swift (it’s part of the iOS SDK).

